int init_ast(void) {
    node_kinds = array_new(0);
    node_data = array_new(0);
    node_extra = array_new(0);
    node_extra2 = array_new(0);
    node_names = array_new(0);
    node_tnames = array_new(0);
    child_lists = array_new(0);
    node_count = 0;
    child_count = 0;
    return 0;
}

int new_node(int kind, int data, int extra, int extra2, const char* name) {
    int idx = node_count;
    array_push(node_kinds, kind);
    array_push(node_data, data);
    array_push(node_extra, extra);
    array_push(node_extra2, extra2);
    array_push(node_names, (long long)name);
    array_push(node_tnames, (long long)"");
    node_count = (node_count + 1);
    return idx;
}

int flush_children(int temp) {
    int start = child_count;
    int i = 0;
    while ((i < array_len(temp))) {
        array_push(child_lists, array_get(temp, i));
        child_count = (child_count + 1);
        i = (i + 1);
    }
    return start;
}

int nk(int idx) {
    return array_get(node_kinds, idx);
}

int nd(int idx) {
    return array_get(node_data, idx);
}

int ne(int idx) {
    return array_get(node_extra, idx);
}

int ne2(int idx) {
    return array_get(node_extra2, idx);
}

const char* nn(int idx) {
    return (const char*)(array_get(node_names, idx));
}

const char* nt(int idx) {
    return (const char*)(array_get(node_tnames, idx));
}

int set_nt(int idx, const char* t) {
    array_set(node_tnames, idx, (long long)t);
    return 0;
}

int child(int start, int i) {
    return array_get(child_lists, (start + i));
}

int parse_primary(void) {
    int t = peek();
    if ((t == TK_NUM())) {
        return new_node(NK_INT_LIT(), 0, 0, 0, advance_val());
    }
    if ((t == TK_STR())) {
        return new_node(NK_STR_LIT(), 0, 0, 0, advance_val());
    }
    if ((t == TK_KW_TRUE())) {
        advance();
        return new_node(NK_BOOL_LIT(), 1, 0, 0, "true");
    }
    if ((t == TK_KW_FALSE())) {
        advance();
        return new_node(NK_BOOL_LIT(), 0, 0, 0, "false");
    }
    if ((t == TK_IDENT())) {
        return new_node(NK_IDENT(), 0, 0, 0, advance_val());
    }
    if ((t == TK_LPAREN())) {
        advance();
        int inner = parse_expr();
        expect(TK_RPAREN(), "')'");
        return inner;
    }
    advance();
    return new_node(NK_INT_LIT(), 0, 0, 0, "0");
}

int parse_postfix(void) {
    int node = parse_primary();
    while (1) {
        if ((peek() == TK_LPAREN())) {
            advance();
            int args = array_new(0);
            while (((peek() != TK_RPAREN()) && (peek() != TK_EOF()))) {
                array_push(args, parse_expr());
                if ((peek() != TK_RPAREN())) {
                    expect(TK_COMMA(), "','");
                }
            }
            expect(TK_RPAREN(), "')'");
            int start = flush_children(args);
            node = new_node(NK_CALL(), node, start, array_len(args), "");
        } else {
            return node;
        }
    }
    return node;
}

int parse_unary(void) {
    if ((peek() == TK_MINUS())) {
        advance();
        return new_node(NK_UNARY(), parse_postfix(), 31, 0, "-");
    }
    if ((peek() == TK_NOT())) {
        advance();
        return new_node(NK_UNARY(), parse_postfix(), 43, 0, "!");
    }
    return parse_postfix();
}

int parse_factor(void) {
    int left = parse_unary();
    while ((((peek() == TK_STAR()) || (peek() == TK_SLASH())) || (peek() == TK_MOD()))) {
        int op = advance();
        int right = parse_unary();
        const char* name = "*";
        if ((op == TK_SLASH())) {
            name = "/";
        }
        if ((op == TK_MOD())) {
            name = "%";
        }
        left = new_node(NK_BINARY(), left, right, op, name);
    }
    return left;
}

int parse_term(void) {
    int left = parse_factor();
    while (((peek() == TK_PLUS()) || (peek() == TK_MINUS()))) {
        int op = advance();
        int right = parse_factor();
        const char* name = "+";
        if ((op == TK_MINUS())) {
            name = "-";
        }
        left = new_node(NK_BINARY(), left, right, op, name);
    }
    return left;
}

int parse_comparison(void) {
    int left = parse_term();
    while (((((peek() == TK_LT()) || (peek() == TK_GT())) || (peek() == TK_LTE())) || (peek() == TK_GTE()))) {
        int op = advance();
        int right = parse_term();
        const char* name = "<";
        if ((op == TK_GT())) {
            name = ">";
        }
        if ((op == TK_LTE())) {
            name = "<=";
        }
        if ((op == TK_GTE())) {
            name = ">=";
        }
        left = new_node(NK_BINARY(), left, right, op, name);
    }
    return left;
}

int parse_equality(void) {
    int left = parse_comparison();
    while (((peek() == TK_EQ()) || (peek() == TK_NEQ()))) {
        int op = advance();
        int right = parse_comparison();
        const char* name = "==";
        if ((op == TK_NEQ())) {
            name = "!=";
        }
        left = new_node(NK_BINARY(), left, right, op, name);
    }
    return left;
}

int parse_and(void) {
    int left = parse_equality();
    while ((peek() == TK_AND())) {
        advance();
        left = new_node(NK_BINARY(), left, parse_equality(), TK_AND(), "&&");
    }
    return left;
}

int parse_expr(void) {
    int left = parse_and();
    while ((peek() == TK_OR())) {
        advance();
        left = new_node(NK_BINARY(), left, parse_and(), TK_OR(), "||");
    }
    return left;
}

int parse_block(void) {
    expect(TK_LBRACE(), "'{'");
    int stmts = array_new(0);
    while (((peek() != TK_RBRACE()) && (peek() != TK_EOF()))) {
        array_push(stmts, parse_stmt());
    }
    expect(TK_RBRACE(), "'}'");
    int start = flush_children(stmts);
    return new_node(NK_BLOCK(), start, array_len(stmts), 0, "");
}

const char* parse_type(void) {
    int t = peek();
    if ((t == TK_KW_I32())) {
        advance();
        return "i32";
    }
    if ((t == TK_KW_I64())) {
        advance();
        return "i64";
    }
    if ((t == TK_KW_F64())) {
        advance();
        return "f64";
    }
    if ((t == TK_KW_BOOL())) {
        advance();
        return "bool";
    }
    if ((t == TK_KW_STRING())) {
        advance();
        return "string";
    }
    if ((t == TK_IDENT())) {
        return advance_val();
    }
    return "unknown";
}

int parse_stmt(void) {
    if (((peek() == TK_KW_LET()) || (peek() == TK_KW_VAR()))) {
        int is_var = 0;
        if ((peek() == TK_KW_VAR())) {
            is_var = 1;
        }
        advance();
        const char* name = advance_val();
        const char* vtype = "i32";
        if (match_tok(TK_COLON())) {
            vtype = parse_type();
        }
        int init = (0 - 1);
        if (match_tok(TK_ASSIGN())) {
            init = parse_expr();
        }
        expect(TK_SEMI(), "';'");
        int vnode = new_node(NK_LET(), init, is_var, 0, name);
        set_nt(vnode, vtype);
        return vnode;
    }
    if ((peek() == TK_KW_RETURN())) {
        advance();
        int val = (0 - 1);
        if ((peek() != TK_SEMI())) {
            val = parse_expr();
        }
        expect(TK_SEMI(), "';'");
        return new_node(NK_RETURN(), val, 0, 0, "");
    }
    if ((peek() == TK_KW_IF())) {
        advance();
        int cond = parse_expr();
        int then_b = parse_block();
        int else_b = (0 - 1);
        if (match_tok(TK_KW_ELSE())) {
            if ((peek() == TK_KW_IF())) {
                else_b = parse_stmt();
            } else {
                else_b = parse_block();
            }
        }
        return new_node(NK_IF(), cond, then_b, else_b, "");
    }
    if ((peek() == TK_KW_WHILE())) {
        advance();
        int cond = parse_expr();
        int body = parse_block();
        return new_node(NK_WHILE(), cond, body, 0, "");
    }
    if ((peek() == TK_LBRACE())) {
        return parse_block();
    }
    int expr = parse_expr();
    if (match_tok(TK_ASSIGN())) {
        int val = parse_expr();
        expect(TK_SEMI(), "';'");
        return new_node(NK_ASSIGN(), expr, val, 0, "");
    }
    expect(TK_SEMI(), "';'");
    return new_node(NK_EXPR_STMT(), expr, 0, 0, "");
}

int parse_fn_decl(void) {
    const char* name = advance_val();
    expect(TK_LPAREN(), "'('");
    int params = array_new(0);
    while (((peek() != TK_RPAREN()) && (peek() != TK_EOF()))) {
        const char* pname = advance_val();
        expect(TK_COLON(), "':'");
        const char* ptype = parse_type();
        int pnode = new_node(NK_LET(), (0 - 1), 0, 0, pname);
        set_nt(pnode, ptype);
        array_push(params, pnode);
        if ((peek() != TK_RPAREN())) {
            expect(TK_COMMA(), "','");
        }
    }
    expect(TK_RPAREN(), "')'");
    const char* ret_type = "void";
    if (match_tok(TK_ARROW())) {
        ret_type = parse_type();
    }
    int body = (0 - 1);
    if ((peek() == TK_SEMI())) {
        advance();
    } else {
        body = parse_block();
    }
    int ps = flush_children(params);
    int fn_node = new_node(NK_FN_DECL(), body, ps, array_len(params), name);
    set_nt(fn_node, ret_type);
    return fn_node;
}

int parse_global_var(void) {
    const char* name = advance_val();
    const char* gtype = "i32";
    if (match_tok(TK_COLON())) {
        gtype = parse_type();
    }
    int init = (0 - 1);
    if (match_tok(TK_ASSIGN())) {
        init = parse_expr();
    }
    expect(TK_SEMI(), "';'");
    int gnode = new_node(NK_VAR_DECL(), init, 0, 0, name);
    set_nt(gnode, gtype);
    return gnode;
}

int parse_program(void) {
    int decls = array_new(0);
    while ((peek() != TK_EOF())) {
        if ((peek() == TK_KW_FN())) {
            advance();
            array_push(decls, parse_fn_decl());
        } else {
            if ((peek() == TK_KW_VAR())) {
                advance();
                array_push(decls, parse_global_var());
            } else {
                advance();
            }
        }
    }
    int start = flush_children(decls);
    return new_node(NK_PROGRAM(), start, array_len(decls), 0, "");
}

