int init_use_system(void) {
    use_included = array_new(0);
    return 0;
}

int use_already_included(const char* path) {
    int i = 0;
    while ((i < array_len(use_included))) {
        if ((strcmp((const char*)(array_get(use_included, i)), path) == 0)) {
            return 1;
        }
        i = (i + 1);
    }
    return 0;
}

const char* get_dir(const char* path) {
    int last_sep = (0 - 1);
    int i = 0;
    while ((i < (int)strlen(path))) {
        int c = (int)path[i];
        if (((c == 47) || (c == 92))) {
            last_sep = i;
        }
        i = (i + 1);
    }
    if ((last_sep >= 0)) {
        return m_substr(path, 0, (last_sep + 1));
    }
    return "";
}

const char* resolve_uses(const char* src, const char* base_dir) {
    const char* result = "";
    int pos = 0;
    while ((pos < (int)strlen(src))) {
        int line_start = pos;
        while (((pos < (int)strlen(src)) && (((int)src[pos] == 32) || ((int)src[pos] == 9)))) {
            pos = (pos + 1);
        }
        if ((((pos + 4) <= (int)strlen(src)) && (strcmp(m_substr(src, pos, 4), "use ") == 0))) {
            pos = (pos + 4);
            while (((pos < (int)strlen(src)) && ((int)src[pos] == 32))) {
                pos = (pos + 1);
            }
            if (((pos < (int)strlen(src)) && ((int)src[pos] == 34))) {
                pos = (pos + 1);
                int path_start = pos;
                while (((pos < (int)strlen(src)) && ((int)src[pos] != 34))) {
                    pos = (pos + 1);
                }
                if ((pos < (int)strlen(src))) {
                    const char* path = m_substr(src, path_start, (pos - path_start));
                    pos = (pos + 1);
                    while (((pos < (int)strlen(src)) && (((int)src[pos] == 32) || ((int)src[pos] == 9)))) {
                        pos = (pos + 1);
                    }
                    if (((pos < (int)strlen(src)) && ((int)src[pos] == 59))) {
                        pos = (pos + 1);
                    }
                    if (((pos < (int)strlen(src)) && ((int)src[pos] == 13))) {
                        pos = (pos + 1);
                    }
                    if (((pos < (int)strlen(src)) && ((int)src[pos] == 10))) {
                        pos = (pos + 1);
                    }
                    const char* full_path = path;
                    if (((int)strlen(base_dir) > 0)) {
                        int first = (int)path[0];
                        if (((first != 47) && (first != 92))) {
                            if ((((int)strlen(path) < 2) || ((int)path[1] != 58))) {
                                full_path = m_str_concat(base_dir, path);
                            }
                        }
                    }
                    if ((use_already_included(full_path) == 0)) {
                        array_push(use_included, (long long)full_path);
                        const char* inc_src = read_file(full_path);
                        const char* inc_dir = get_dir(full_path);
                        const char* resolved = resolve_uses(inc_src, inc_dir);
                        result = m_str_concat(result, resolved);
                        result = m_str_concat(result, "\n");
                    }
                }
            }
        } else {
            pos = line_start;
            while (((pos < (int)strlen(src)) && ((int)src[pos] != 10))) {
                pos = (pos + 1);
            }
            result = m_str_concat(result, m_substr(src, line_start, (pos - line_start)));
            if (((pos < (int)strlen(src)) && ((int)src[pos] == 10))) {
                result = m_str_concat(result, "\n");
                pos = (pos + 1);
            }
        }
    }
    return result;
}

const char* cc(const char* a, const char* b) {
    return m_str_concat(a, b);
}

const char* c_type(const char* t) {
    if ((strcmp(t, "i32") == 0)) {
        return "int";
    }
    if ((strcmp(t, "i64") == 0)) {
        return "long long";
    }
    if ((strcmp(t, "f64") == 0)) {
        return "double";
    }
    if ((strcmp(t, "bool") == 0)) {
        return "int";
    }
    if ((strcmp(t, "string") == 0)) {
        return "const char*";
    }
    if ((strcmp(t, "void") == 0)) {
        return "void";
    }
    if ((strcmp(t, "") == 0)) {
        return "int";
    }
    return "int";
}

const char* make_indent(int level) {
    const char* s = "";
    int i = 0;
    while ((i < level)) {
        s = cc(s, "    ");
        i = (i + 1);
    }
    return s;
}

int str_contains(const char* haystack, const char* needle) {
    if (((int)strlen(needle) > (int)strlen(haystack))) {
        return 0;
    }
    int i = 0;
    while ((i <= ((int)strlen(haystack) - (int)strlen(needle)))) {
        if ((strcmp(m_substr(haystack, i, (int)strlen(needle)), needle) == 0)) {
            return 1;
        }
        i = (i + 1);
    }
    return 0;
}

int init_c_types(void) {
    c_fn_names = array_new(0);
    c_fn_rets = array_new(0);
    c_fn_pcounts = array_new(0);
    c_fn_poffsets = array_new(0);
    c_fn_ptypes = array_new(0);
    c_vr_names = array_new(0);
    c_vr_types = array_new(0);
    return 0;
}

int c_add_func(const char* name, const char* ret, int pstart, int pcount) {
    array_push(c_fn_names, (long long)name);
    array_push(c_fn_rets, (long long)ret);
    int offset = array_len(c_fn_ptypes);
    array_push(c_fn_poffsets, offset);
    array_push(c_fn_pcounts, pcount);
    int pi = 0;
    while ((pi < pcount)) {
        int pnode = child(pstart, pi);
        array_push(c_fn_ptypes, (long long)nt(pnode));
        pi = (pi + 1);
    }
    return 0;
}

const char* c_func_ret(const char* name) {
    int i = 0;
    while ((i < array_len(c_fn_names))) {
        if ((strcmp((const char*)(array_get(c_fn_names, i)), name) == 0)) {
            return (const char*)(array_get(c_fn_rets, i));
        }
        i = (i + 1);
    }
    return "i32";
}

int c_add_var(const char* name, const char* t) {
    int i = 0;
    while ((i < array_len(c_vr_names))) {
        if ((strcmp((const char*)(array_get(c_vr_names, i)), name) == 0)) {
            array_set(c_vr_types, i, (long long)t);
            return 0;
        }
        i = (i + 1);
    }
    array_push(c_vr_names, (long long)name);
    array_push(c_vr_types, (long long)t);
    return 0;
}

const char* c_var_type(const char* name) {
    int i = 0;
    while ((i < array_len(c_vr_names))) {
        if ((strcmp((const char*)(array_get(c_vr_names, i)), name) == 0)) {
            return (const char*)(array_get(c_vr_types, i));
        }
        i = (i + 1);
    }
    return "i32";
}

int c_clear_vars(void) {
    c_vr_names = array_new(0);
    c_vr_types = array_new(0);
    return 0;
}

const char* c_func_param_type(const char* name, int pidx) {
    int i = 0;
    while ((i < array_len(c_fn_names))) {
        if ((strcmp((const char*)(array_get(c_fn_names, i)), name) == 0)) {
            int count = array_get(c_fn_pcounts, i);
            if ((pidx < count)) {
                int offset = array_get(c_fn_poffsets, i);
                return (const char*)(array_get(c_fn_ptypes, (offset + pidx)));
            }
            return "i32";
        }
        i = (i + 1);
    }
    return "i32";
}

const char* infer_type(int idx) {
    if ((idx < 0)) {
        return "i32";
    }
    int kind = nk(idx);
    if ((kind == NK_INT_LIT())) {
        return "i32";
    }
    if ((kind == NK_STR_LIT())) {
        return "string";
    }
    if ((kind == NK_BOOL_LIT())) {
        return "bool";
    }
    if ((kind == NK_IDENT())) {
        return c_var_type(nn(idx));
    }
    if ((kind == NK_BINARY())) {
        int op = ne2(idx);
        if (((((((((op == TK_EQ()) || (op == TK_NEQ())) || (op == TK_LT())) || (op == TK_GT())) || (op == TK_LTE())) || (op == TK_GTE())) || (op == TK_AND())) || (op == TK_OR()))) {
            return "bool";
        }
        return infer_type(nd(idx));
    }
    if ((kind == NK_UNARY())) {
        return "i32";
    }
    if ((kind == NK_CALL())) {
        int callee = nd(idx);
        const char* name = nn(callee);
        if ((strcmp(name, "int_to_str") == 0)) {
            return "string";
        }
        if ((strcmp(name, "str_concat") == 0)) {
            return "string";
        }
        if ((strcmp(name, "substr") == 0)) {
            return "string";
        }
        if ((strcmp(name, "char_to_str") == 0)) {
            return "string";
        }
        if ((strcmp(name, "read_file") == 0)) {
            return "string";
        }
        if ((strcmp(name, "argv") == 0)) {
            return "string";
        }
        if ((strcmp(name, "len") == 0)) {
            return "i32";
        }
        if ((strcmp(name, "char_at") == 0)) {
            return "i32";
        }
        if ((strcmp(name, "str_eq") == 0)) {
            return "bool";
        }
        if ((strcmp(name, "array_new") == 0)) {
            return "i32";
        }
        if ((strcmp(name, "array_len") == 0)) {
            return "i32";
        }
        if ((strcmp(name, "array_get") == 0)) {
            return "i32";
        }
        if ((strcmp(name, "argc") == 0)) {
            return "i32";
        }
        return c_func_ret(name);
    }
    return "i32";
}

const char* gen_c_str_arg(int idx) {
    const char* expr = gen_c_expr(idx);
    if ((strcmp(infer_type(idx), "string") == 0)) {
        return expr;
    }
    return cc("(const char*)(", cc(expr, ")"));
}

const char* gen_c_expr(int idx) {
    if ((idx < 0)) {
        return "0";
    }
    int kind = nk(idx);
    if ((kind == NK_INT_LIT())) {
        return nn(idx);
    }
    if ((kind == NK_STR_LIT())) {
        return cc("\"", cc(nn(idx), "\""));
    }
    if ((kind == NK_BOOL_LIT())) {
        if ((nd(idx) != 0)) {
            return "1";
        }
        return "0";
    }
    if ((kind == NK_IDENT())) {
        return nn(idx);
    }
    if ((kind == NK_UNARY())) {
        const char* operand = gen_c_expr(nd(idx));
        int op = ne(idx);
        if ((op == 31)) {
            return cc("(-", cc(operand, ")"));
        }
        if ((op == 43)) {
            return cc("(!", cc(operand, ")"));
        }
        return operand;
    }
    if ((kind == NK_BINARY())) {
        const char* left = gen_c_expr(nd(idx));
        const char* right = gen_c_expr(ne(idx));
        int op = ne2(idx);
        const char* op_str = " + ";
        if ((op == TK_MINUS())) {
            op_str = " - ";
        }
        if ((op == TK_STAR())) {
            op_str = " * ";
        }
        if ((op == TK_SLASH())) {
            op_str = " / ";
        }
        if ((op == TK_MOD())) {
            op_str = " % ";
        }
        if ((op == TK_EQ())) {
            op_str = " == ";
        }
        if ((op == TK_NEQ())) {
            op_str = " != ";
        }
        if ((op == TK_LT())) {
            op_str = " < ";
        }
        if ((op == TK_GT())) {
            op_str = " > ";
        }
        if ((op == TK_LTE())) {
            op_str = " <= ";
        }
        if ((op == TK_GTE())) {
            op_str = " >= ";
        }
        if ((op == TK_AND())) {
            op_str = " && ";
        }
        if ((op == TK_OR())) {
            op_str = " || ";
        }
        return cc("(", cc(left, cc(op_str, cc(right, ")"))));
    }
    if ((kind == NK_CALL())) {
        int callee_idx = nd(idx);
        int arg_start = ne(idx);
        int argc = ne2(idx);
        const char* name = nn(callee_idx);
        if ((strcmp(name, "print") == 0)) {
            if ((argc >= 1)) {
                int arg = child(arg_start, 0);
                const char* atype = infer_type(arg);
                if ((strcmp(atype, "string") == 0)) {
                    return cc("printf(\"%s\", ", cc(gen_c_str_arg(arg), ")"));
                }
                return cc("printf(\"%d\", ", cc(gen_c_expr(arg), ")"));
            }
            return "0";
        }
        if ((strcmp(name, "println") == 0)) {
            if ((argc >= 1)) {
                int arg = child(arg_start, 0);
                const char* atype = infer_type(arg);
                if ((strcmp(atype, "string") == 0)) {
                    return cc("printf(\"%s\\n\", ", cc(gen_c_str_arg(arg), ")"));
                }
                return cc("printf(\"%d\\n\", ", cc(gen_c_expr(arg), ")"));
            }
            return "printf(\"\\n\")";
        }
        if ((strcmp(name, "len") == 0)) {
            if ((argc >= 1)) {
                return cc("(int)strlen(", cc(gen_c_str_arg(child(arg_start, 0)), ")"));
            }
            return "0";
        }
        if ((strcmp(name, "str_eq") == 0)) {
            if ((argc >= 2)) {
                return cc("(strcmp(", cc(gen_c_str_arg(child(arg_start, 0)), cc(", ", cc(gen_c_str_arg(child(arg_start, 1)), ") == 0)"))));
            }
            return "0";
        }
        if ((strcmp(name, "int_to_str") == 0)) {
            if ((argc >= 1)) {
                return cc("m_int_to_str(", cc(gen_c_expr(child(arg_start, 0)), ")"));
            }
            return "\"\"";
        }
        if ((strcmp(name, "str_concat") == 0)) {
            if ((argc >= 2)) {
                return cc("m_str_concat(", cc(gen_c_str_arg(child(arg_start, 0)), cc(", ", cc(gen_c_str_arg(child(arg_start, 1)), ")"))));
            }
            return "\"\"";
        }
        if ((strcmp(name, "char_at") == 0)) {
            if ((argc >= 2)) {
                return cc("(int)", cc(gen_c_str_arg(child(arg_start, 0)), cc("[", cc(gen_c_expr(child(arg_start, 1)), "]"))));
            }
            return "0";
        }
        if ((strcmp(name, "substr") == 0)) {
            if ((argc >= 3)) {
                return cc("m_substr(", cc(gen_c_str_arg(child(arg_start, 0)), cc(", ", cc(gen_c_expr(child(arg_start, 1)), cc(", ", cc(gen_c_expr(child(arg_start, 2)), ")"))))));
            }
            return "\"\"";
        }
        if ((strcmp(name, "char_to_str") == 0)) {
            if ((argc >= 1)) {
                return cc("m_char_to_str(", cc(gen_c_expr(child(arg_start, 0)), ")"));
            }
            return "\"\"";
        }
        if ((strcmp(name, "array_push") == 0)) {
            if ((argc >= 2)) {
                int val_arg = child(arg_start, 1);
                const char* val_type = infer_type(val_arg);
                if ((strcmp(val_type, "string") == 0)) {
                    return cc("array_push(", cc(gen_c_expr(child(arg_start, 0)), cc(", (long long)", cc(gen_c_expr(val_arg), ")"))));
                }
                return cc("array_push(", cc(gen_c_expr(child(arg_start, 0)), cc(", ", cc(gen_c_expr(val_arg), ")"))));
            }
            return "0";
        }
        if ((strcmp(name, "array_set") == 0)) {
            if ((argc >= 3)) {
                int val_arg = child(arg_start, 2);
                const char* val_type = infer_type(val_arg);
                if ((strcmp(val_type, "string") == 0)) {
                    return cc("array_set(", cc(gen_c_expr(child(arg_start, 0)), cc(", ", cc(gen_c_expr(child(arg_start, 1)), cc(", (long long)", cc(gen_c_expr(val_arg), ")"))))));
                }
                return cc("array_set(", cc(gen_c_expr(child(arg_start, 0)), cc(", ", cc(gen_c_expr(child(arg_start, 1)), cc(", ", cc(gen_c_expr(val_arg), ")"))))));
            }
            return "0";
        }
        const char* result = cc(name, "(");
        int i = 0;
        while ((i < argc)) {
            if ((i > 0)) {
                result = cc(result, ", ");
            }
            int arg_node = child(arg_start, i);
            const char* arg_expr = gen_c_expr(arg_node);
            const char* pt = c_func_param_type(name, i);
            if (((strcmp(pt, "string") == 0) && (!(strcmp(infer_type(arg_node), "string") == 0)))) {
                arg_expr = cc("(const char*)(", cc(arg_expr, ")"));
            }
            result = cc(result, arg_expr);
            i = (i + 1);
        }
        return cc(result, ")");
    }
    return "0";
}

const char* gen_c_stmt(int idx, int level) {
    if ((idx < 0)) {
        return "";
    }
    int kind = nk(idx);
    const char* ind = make_indent(level);
    if ((kind == NK_LET())) {
        const char* name = nn(idx);
        const char* vt = nt(idx);
        c_add_var(name, vt);
        const char* type_str = c_type(vt);
        int init = nd(idx);
        if ((init >= 0)) {
            const char* iexpr = gen_c_expr(init);
            if (((strcmp(vt, "string") == 0) && (!(strcmp(infer_type(init), "string") == 0)))) {
                return cc(ind, cc(type_str, cc(" ", cc(name, cc(" = (const char*)(", cc(iexpr, ");\n"))))));
            }
            return cc(ind, cc(type_str, cc(" ", cc(name, cc(" = ", cc(iexpr, ";\n"))))));
        }
        if ((strcmp(vt, "string") == 0)) {
            return cc(ind, cc(type_str, cc(" ", cc(name, " = \"\";\n"))));
        }
        return cc(ind, cc(type_str, cc(" ", cc(name, " = 0;\n"))));
    }
    if ((kind == NK_ASSIGN())) {
        int target = nd(idx);
        int val = ne(idx);
        const char* vexpr = gen_c_expr(val);
        const char* ttype = c_var_type(nn(target));
        if (((strcmp(ttype, "string") == 0) && (!(strcmp(infer_type(val), "string") == 0)))) {
            return cc(ind, cc(nn(target), cc(" = (const char*)(", cc(vexpr, ");\n"))));
        }
        return cc(ind, cc(nn(target), cc(" = ", cc(vexpr, ";\n"))));
    }
    if ((kind == NK_RETURN())) {
        int val = nd(idx);
        if ((val >= 0)) {
            const char* rexpr = gen_c_expr(val);
            if (((strcmp((const char*)(c_current_fn_ret), "string") == 0) && (!(strcmp(infer_type(val), "string") == 0)))) {
                return cc(ind, cc("return (const char*)(", cc(rexpr, ");\n")));
            }
            return cc(ind, cc("return ", cc(rexpr, ";\n")));
        }
        return cc(ind, "return;\n");
    }
    if ((kind == NK_IF())) {
        int cond = nd(idx);
        int then_b = ne(idx);
        int else_b = ne2(idx);
        const char* result = cc(ind, cc("if (", cc(gen_c_expr(cond), ") {\n")));
        result = cc(result, gen_c_stmt(then_b, (level + 1)));
        if ((else_b >= 0)) {
            result = cc(result, cc(ind, "} else {\n"));
            result = cc(result, gen_c_stmt(else_b, (level + 1)));
        }
        result = cc(result, cc(ind, "}\n"));
        return result;
    }
    if ((kind == NK_WHILE())) {
        int cond = nd(idx);
        int body = ne(idx);
        const char* result = cc(ind, cc("while (", cc(gen_c_expr(cond), ") {\n")));
        result = cc(result, gen_c_stmt(body, (level + 1)));
        result = cc(result, cc(ind, "}\n"));
        return result;
    }
    if ((kind == NK_BLOCK())) {
        int start = nd(idx);
        int count = ne(idx);
        const char* result = "";
        int i = 0;
        while ((i < count)) {
            result = cc(result, gen_c_stmt(child(start, i), level));
            i = (i + 1);
        }
        return result;
    }
    if ((kind == NK_EXPR_STMT())) {
        return cc(ind, cc(gen_c_expr(nd(idx)), ";\n"));
    }
    return "";
}

const char* gen_c_func(int idx) {
    const char* name = nn(idx);
    int body = nd(idx);
    int param_start = ne(idx);
    int param_count = ne2(idx);
    const char* ret_type = c_type(nt(idx));
    c_current_fn_ret = nt(idx);
    c_clear_vars();
    int i = 0;
    while ((i < param_count)) {
        int pnode = child(param_start, i);
        c_add_var(nn(pnode), nt(pnode));
        i = (i + 1);
    }
    const char* cname = name;
    if ((strcmp(name, "main") == 0)) {
        cname = "m_main";
    }
    const char* sig = cc(ret_type, cc(" ", cc(cname, "(")));
    if ((param_count == 0)) {
        sig = cc(sig, "void");
    } else {
        i = 0;
        while ((i < param_count)) {
            if ((i > 0)) {
                sig = cc(sig, ", ");
            }
            int pnode = child(param_start, i);
            sig = cc(sig, cc(c_type(nt(pnode)), cc(" ", nn(pnode))));
            i = (i + 1);
        }
    }
    sig = cc(sig, ")");
    const char* result = cc(sig, " {\n");
    if ((body >= 0)) {
        if ((nk(body) == NK_BLOCK())) {
            int start = nd(body);
            int count = ne(body);
            int j = 0;
            while ((j < count)) {
                result = cc(result, gen_c_stmt(child(start, j), 1));
                j = (j + 1);
            }
        } else {
            result = cc(result, gen_c_stmt(body, 1));
        }
    }
    result = cc(result, "}\n");
    return result;
}

const char* c_runtime(void) {
    const char* r = "// M runtime — strings (malloc-based)\n";
    r = cc(r, "static const char* m_str_alloc(const char* s, int len) {\n");
    r = cc(r, "    char* p = (char*)malloc(len + 1);\n");
    r = cc(r, "    memcpy(p, s, len); p[len] = 0;\n");
    r = cc(r, "    return p;\n");
    r = cc(r, "}\n");
    r = cc(r, "static const char* m_str_concat(const char* a, const char* b) {\n");
    r = cc(r, "    int la = strlen(a), lb = strlen(b);\n");
    r = cc(r, "    char* p = (char*)malloc(la + lb + 1);\n");
    r = cc(r, "    memcpy(p, a, la); memcpy(p+la, b, lb); p[la+lb] = 0;\n");
    r = cc(r, "    return p;\n");
    r = cc(r, "}\n");
    r = cc(r, "static const char* m_substr(const char* s, int start, int len) {\n");
    r = cc(r, "    return m_str_alloc(s + start, len);\n");
    r = cc(r, "}\n");
    r = cc(r, "static const char* m_int_to_str(int n) {\n");
    r = cc(r, "    char* p = (char*)malloc(32);\n");
    r = cc(r, "    sprintf(p, \"%d\", n);\n");
    r = cc(r, "    return p;\n");
    r = cc(r, "}\n");
    r = cc(r, "static const char* m_char_to_str(int c) {\n");
    r = cc(r, "    char* p = (char*)malloc(2);\n");
    r = cc(r, "    p[0] = (char)c; p[1] = 0;\n");
    r = cc(r, "    return p;\n");
    r = cc(r, "}\n\n");
    r = cc(r, "// M runtime — arrays (dynamic, long long values)\n");
    r = cc(r, "typedef struct { long long* data; int len; int cap; } MArray;\n");
    r = cc(r, "static MArray _arrays[65536];\n");
    r = cc(r, "static int _arr_count = 0;\n");
    r = cc(r, "static int array_new(int cap) {\n");
    r = cc(r, "    int id = _arr_count++;\n");
    r = cc(r, "    _arrays[id].cap = cap > 0 ? cap : 8;\n");
    r = cc(r, "    _arrays[id].data = (long long*)malloc(_arrays[id].cap * sizeof(long long));\n");
    r = cc(r, "    _arrays[id].len = 0;\n");
    r = cc(r, "    return id;\n");
    r = cc(r, "}\n");
    r = cc(r, "static void array_push(int id, long long val) {\n");
    r = cc(r, "    MArray* a = &_arrays[id];\n");
    r = cc(r, "    if (a->len >= a->cap) { a->cap *= 2; a->data = (long long*)realloc(a->data, a->cap * sizeof(long long)); }\n");
    r = cc(r, "    a->data[a->len++] = val;\n");
    r = cc(r, "}\n");
    r = cc(r, "static long long array_get(int id, int idx) { return _arrays[id].data[idx]; }\n");
    r = cc(r, "static void array_set(int id, int idx, long long val) { _arrays[id].data[idx] = val; }\n");
    r = cc(r, "static int array_len(int id) { return _arrays[id].len; }\n\n");
    r = cc(r, "// M runtime — system builtins\n");
    r = cc(r, "static int _m_argc;\n");
    r = cc(r, "static char** _m_argv;\n");
    r = cc(r, "static int argc(void) { return _m_argc; }\n");
    r = cc(r, "static const char* argv(int n) { return _m_argv[n]; }\n");
    r = cc(r, "static const char* read_file(const char* path) {\n");
    r = cc(r, "    FILE* f = fopen(path, \"rb\");\n");
    r = cc(r, "    if (!f) return \"\";\n");
    r = cc(r, "    fseek(f, 0, SEEK_END);\n");
    r = cc(r, "    long sz = ftell(f);\n");
    r = cc(r, "    fseek(f, 0, SEEK_SET);\n");
    r = cc(r, "    char* buf = (char*)malloc(sz + 1);\n");
    r = cc(r, "    fread(buf, 1, sz, f);\n");
    r = cc(r, "    buf[sz] = 0;\n");
    r = cc(r, "    fclose(f);\n");
    r = cc(r, "    return buf;\n");
    r = cc(r, "}\n");
    r = cc(r, "static void write_file(const char* path, const char* content) {\n");
    r = cc(r, "    FILE* f = fopen(path, \"wb\");\n");
    r = cc(r, "    if (f) { fputs(content, f); fclose(f); }\n");
    r = cc(r, "}\n\n");
    return r;
}

const char* gen_c_program(int root) {
    int start = nd(root);
    int count = ne(root);
    init_c_types();
    int i = 0;
    while ((i < count)) {
        int decl = child(start, i);
        if ((nk(decl) == NK_FN_DECL())) {
            c_add_func(nn(decl), nt(decl), ne(decl), ne2(decl));
        }
        if ((nk(decl) == NK_VAR_DECL())) {
            c_add_var(nn(decl), nt(decl));
        }
        i = (i + 1);
    }
    const char* result = "// Generated by Machine M -> C transpiler\n";
    result = cc(result, "#include <stdio.h>\n");
    result = cc(result, "#include <stdlib.h>\n");
    result = cc(result, "#include <string.h>\n\n");
    result = cc(result, c_runtime());
    i = 0;
    while ((i < count)) {
        int decl = child(start, i);
        if (((nk(decl) == NK_FN_DECL()) && (nd(decl) >= 0))) {
            const char* name = nn(decl);
            if ((!(strcmp(name, "main") == 0))) {
                const char* ret = c_type(nt(decl));
                const char* fwd = cc(ret, cc(" ", cc(name, "(")));
                int ps = ne(decl);
                int pc = ne2(decl);
                if ((pc == 0)) {
                    fwd = cc(fwd, "void");
                } else {
                    int j = 0;
                    while ((j < pc)) {
                        if ((j > 0)) {
                            fwd = cc(fwd, ", ");
                        }
                        fwd = cc(fwd, c_type(nt(child(ps, j))));
                        j = (j + 1);
                    }
                }
                fwd = cc(fwd, ");\n");
                result = cc(result, fwd);
            }
        }
        i = (i + 1);
    }
    result = cc(result, "\n");
    i = 0;
    while ((i < count)) {
        int decl = child(start, i);
        if ((nk(decl) == NK_VAR_DECL())) {
            const char* name = nn(decl);
            const char* gtype = c_type(nt(decl));
            int init = nd(decl);
            if ((init >= 0)) {
                result = cc(result, cc(gtype, cc(" ", cc(name, cc(" = ", cc(gen_c_expr(init), ";\n"))))));
            } else {
                result = cc(result, cc(gtype, cc(" ", cc(name, " = 0;\n"))));
            }
        }
        i = (i + 1);
    }
    i = 0;
    while ((i < count)) {
        int decl = child(start, i);
        if (((nk(decl) == NK_FN_DECL()) && (nd(decl) >= 0))) {
            result = cc(result, "\n");
            result = cc(result, gen_c_func(decl));
        }
        i = (i + 1);
    }
    result = cc(result, "\nint main(int argc, char** argv) {\n");
    result = cc(result, "    _m_argc = argc;\n");
    result = cc(result, "    _m_argv = argv;\n");
    result = cc(result, "    return m_main();\n");
    result = cc(result, "}\n");
    return result;
}

